// Extract the integration request from the webhook body
const body = $input.first().json.body || $input.first().json;

const action = body.action || 'unknown';
const agentId = body.agent_id || '';
const data = body.data || {};

return {
  action,
  agent_id: agentId,
  // Booking data
  caller_name: data.caller_name || '',
  caller_phone: data.caller_phone || '',
  caller_email: data.caller_email || '',
  caller_address: data.caller_address || '',
  service_requested: data.service_requested || '',
  job_type: data.job_type || '',
  preferred_date: data.preferred_date || '',
  preferred_time_window: data.preferred_time_window || '',
  duration_minutes: data.duration_minutes || 60,
  // For reschedule
  original_date: data.original_date || '',
  new_date: data.new_date || '',
  new_time_window: data.new_time_window || '',
  // For cancel
  appointment_id: data.appointment_id || '',
  // Raw data passthrough
  _raw: body
};

const request = $('Extract Request').first().json;
const clients = $input.first().json;

// Supabase returns array
const client = Array.isArray(clients) ? clients[0] : clients;

if (!client || !client.agent_id) {
  return {
    ...request,
    _error: true,
    _message: 'Client not found for agent_id: ' + request.agent_id,
    calendar_platform: 'none',
    crm_platform: 'none'
  };
}

return {
  ...request,
  _error: false,
  company_name: client.company_name || '',
  calendar_platform: client.calendar_platform || 'none',
  calendar_status: client.calendar_status || 'pending',
  calendar_access_token: client.calendar_access_token || '',
  calendar_refresh_token: client.calendar_refresh_token || '',
  calendar_api_key: client.calendar_api_key || '',
  crm_platform: client.crm_platform || 'none',
  crm_status: client.crm_status || 'pending',
  crm_access_token: client.crm_access_token || '',
  crm_refresh_token: client.crm_refresh_token || '',
  crm_api_key: client.crm_api_key || '',
  booking_buffer_minutes: client.booking_buffer_minutes || 30,
  default_appointment_duration: client.default_appointment_duration || 60,
  booking_confirmation_method: client.booking_confirmation_method || 'email',
  timezone: client.timezone || 'America/Chicago',
  lead_email: client.lead_email || '',
  lead_phone: client.lead_phone || ''
};

// ============================================================
// CHECK AVAILABILITY — Routes to platform-specific calendar API
// ============================================================
const d = $input.first().json;
const platform = d.calendar_platform || 'none';
const status = d.calendar_status || 'pending';

// If calendar not connected yet, return fallback response
if (status !== 'connected' || platform === 'none') {
  return {
    available: false,
    reason: 'calendar_not_connected',
    message: 'Calendar integration is not yet connected. Please collect caller details for manual follow-up.',
    alternatives: []
  };
}

// Route by platform
const date = d.preferred_date;
const timeWindow = d.preferred_time_window;
const duration = d.duration_minutes || d.default_appointment_duration || 60;
const timezone = d.timezone || 'America/Chicago';

// GOOGLE CALENDAR
if (platform === 'Google Calendar') {
  try {
    // Build time range for the requested window
    const dateObj = new Date(date + 'T00:00:00');
    let startHour, endHour;
    if (timeWindow === 'morning') { startHour = 8; endHour = 12; }
    else if (timeWindow === 'afternoon') { startHour = 12; endHour = 17; }
    else { startHour = 8; endHour = 17; }

    const timeMin = date + `T${String(startHour).padStart(2,'0')}:00:00`;
    const timeMax = date + `T${String(endHour).padStart(2,'0')}:00:00`;

    // Call Google Calendar FreeBusy API
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://www.googleapis.com/calendar/v3/freeBusy',
      headers: {
        'Authorization': 'Bearer ' + d.calendar_access_token,
        'Content-Type': 'application/json'
      },
      body: {
        timeMin: timeMin + 'Z',
        timeMax: timeMax + 'Z',
        timeZone: timezone,
        items: [{ id: 'primary' }]
      },
      json: true
    });

    const busySlots = response.calendars?.primary?.busy || [];
    const isAvailable = busySlots.length === 0;

    return {
      available: isAvailable,
      reason: isAvailable ? 'slot_available' : 'slot_busy',
      message: isAvailable 
        ? `The ${timeWindow} slot on ${date} is available.`
        : `The ${timeWindow} slot on ${date} is not available.`,
      busy_slots: busySlots,
      alternatives: isAvailable ? [] : [
        { date: date, time_window: timeWindow === 'morning' ? 'afternoon' : 'morning' }
      ]
    };
  } catch (err) {
    // Token might be expired, try refresh
    return {
      available: false,
      reason: 'calendar_error',
      message: 'Unable to check calendar availability right now. Please collect caller details for manual follow-up.',
      error: err.message
    };
  }
}

// CALENDLY — uses Calendly API
if (platform === 'Calendly') {
  // Calendly doesn't have a direct free/busy check — availability is managed by event types
  // Return available and let the create_booking handle the actual scheduling
  return {
    available: true,
    reason: 'calendly_assumed_available',
    message: `Calendly slot on ${date} (${timeWindow}) is available.`,
    alternatives: []
  };
}

// JOBBER CALENDAR / HOUSECALL PRO CALENDAR
if (platform === 'Jobber Calendar' || platform === 'Housecall Pro Calendar') {
  // These platforms manage availability through their job scheduling
  // For now, return available and create the job/visit in create_booking
  return {
    available: true,
    reason: 'field_service_assumed_available',
    message: `${timeWindow.charAt(0).toUpperCase() + timeWindow.slice(1)} slot on ${date} is available.`,
    alternatives: []
  };
}

// DEFAULT / UNSUPPORTED
return {
  available: true,
  reason: 'platform_not_integrated',
  message: `Slot on ${date} (${timeWindow}) is tentatively available.`,
  alternatives: []
};

// ============================================================
// CREATE BOOKING — Routes to platform-specific calendar API
// ============================================================
const d = $input.first().json;
const platform = d.calendar_platform || 'none';
const status = d.calendar_status || 'pending';

if (status !== 'connected' || platform === 'none') {
  return {
    success: false,
    reason: 'calendar_not_connected',
    message: 'Calendar not connected. Details captured for manual booking.',
    booking_id: null
  };
}

const date = d.preferred_date;
const timeWindow = d.preferred_time_window;
const duration = d.duration_minutes || d.default_appointment_duration || 60;
const timezone = d.timezone || 'America/Chicago';

// Build start/end times
let startHour = timeWindow === 'morning' ? 8 : 12;
const startTime = date + `T${String(startHour).padStart(2,'0')}:00:00`;
const endMinutes = startHour * 60 + duration;
const endHour = Math.floor(endMinutes / 60);
const endMin = endMinutes % 60;
const endTime = date + `T${String(endHour).padStart(2,'0')}:${String(endMin).padStart(2,'0')}:00`;

// GOOGLE CALENDAR
if (platform === 'Google Calendar') {
  try {
    const event = {
      summary: `${d.service_requested || 'Service Call'} — ${d.caller_name || 'Customer'}`,
      description: [
        `Customer: ${d.caller_name}`,
        `Phone: ${d.caller_phone}`,
        d.caller_email ? `Email: ${d.caller_email}` : '',
        `Address: ${d.caller_address}`,
        `Service: ${d.service_requested}`,
        `Booked by: Syntharra AI Receptionist`
      ].filter(Boolean).join('\n'),
      start: { dateTime: startTime, timeZone: timezone },
      end: { dateTime: endTime, timeZone: timezone },
      location: d.caller_address || ''
    };

    if (d.caller_email) {
      event.attendees = [{ email: d.caller_email }];
    }

    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://www.googleapis.com/calendar/v3/calendars/primary/events',
      headers: {
        'Authorization': 'Bearer ' + d.calendar_access_token,
        'Content-Type': 'application/json'
      },
      body: event,
      json: true
    });

    return {
      success: true,
      reason: 'booked',
      message: `Appointment booked for ${date} (${timeWindow}).`,
      booking_id: response.id,
      calendar_link: response.htmlLink,
      platform: 'Google Calendar'
    };
  } catch (err) {
    return {
      success: false,
      reason: 'calendar_error',
      message: 'Failed to create calendar event. Details captured for manual booking.',
      error: err.message
    };
  }
}

// CALENDLY — would use Calendly API to create an invitee
if (platform === 'Calendly') {
  return {
    success: true,
    reason: 'calendly_placeholder',
    message: 'Booking request logged for Calendly. Integration pending.',
    booking_id: null,
    platform: 'Calendly'
  };
}

// JOBBER
if (platform === 'Jobber Calendar' || platform === 'Jobber') {
  if (!d.crm_api_key && !d.calendar_api_key) {
    return {
      success: false,
      reason: 'no_api_key',
      message: 'Jobber API key not configured. Details captured for manual booking.'
    };
  }

  // Jobber API: Create a Job with a Visit
  // This would use the Jobber GraphQL API
  return {
    success: true,
    reason: 'jobber_placeholder',
    message: `Booking logged for Jobber — ${date} (${timeWindow}).`,
    booking_id: null,
    platform: 'Jobber'
  };
}

// DEFAULT
return {
  success: true,
  reason: 'manual_follow_up',
  message: `Booking details captured for ${date} (${timeWindow}). Team will confirm.`,
  booking_id: null,
  platform: platform
};

// RESCHEDULE — placeholder for platform-specific reschedule logic
const d = $input.first().json;
const platform = d.calendar_platform || 'none';

// Google Calendar: PATCH event with new times
// Jobber: Update visit schedule
// Calendly: Cancel + rebook

return {
  success: true,
  reason: 'reschedule_logged',
  message: `Reschedule request captured: ${d.original_date} → ${d.new_date} (${d.new_time_window}).`,
  platform: platform
};

// CANCEL — placeholder for platform-specific cancellation
const d = $input.first().json;
const platform = d.calendar_platform || 'none';

// Google Calendar: DELETE event
// Jobber: Cancel job/visit
// Calendly: Cancel invitee

return {
  success: true,
  reason: 'cancellation_logged',
  message: 'Cancellation request captured.',
  platform: platform
};

// ============================================================
// CRM PUSH — Creates/updates contact + job in CRM
// Called by the call processor after each call
// ============================================================
const d = $input.first().json;
const platform = d.crm_platform || 'none';
const status = d.crm_status || 'pending';

if (status !== 'connected' || platform === 'none') {
  return {
    success: false,
    reason: 'crm_not_connected',
    message: 'CRM not connected. Lead data captured in Supabase only.'
  };
}

// JOBBER — GraphQL API
if (platform === 'Jobber') {
  // Would create Client + Job via Jobber GraphQL
  // mutation { clientCreate(input: { ... }) { client { id } } }
  return {
    success: true,
    reason: 'jobber_placeholder',
    message: 'Contact and job data logged for Jobber sync.',
    platform: 'Jobber'
  };
}

// HOUSECALL PRO
if (platform === 'Housecall Pro') {
  // Would use HCP API to create customer + job
  return {
    success: true,
    reason: 'hcp_placeholder',
    message: 'Contact and job data logged for HCP sync.',
    platform: 'Housecall Pro'
  };
}

// SERVICETITAN
if (platform === 'ServiceTitan') {
  // Would use ServiceTitan API to create customer + booking
  return {
    success: true,
    reason: 'servicetitan_placeholder',
    message: 'Contact and job data logged for ServiceTitan sync.',
    platform: 'ServiceTitan'
  };
}

// GOHIGHLEVEL
if (platform === 'GoHighLevel') {
  // Would use GHL API to create contact + opportunity
  return {
    success: true,
    reason: 'ghl_placeholder',
    message: 'Contact logged for GoHighLevel sync.',
    platform: 'GoHighLevel'
  };
}

// DEFAULT
return {
  success: true,
  reason: 'crm_logged',
  message: 'Lead data captured. CRM sync pending platform implementation.',
  platform: platform
};

return {
  success: false,
  reason: 'unknown_action',
  message: 'Unknown integration action: ' + ($input.first().json.action || 'none')
};
